import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/installer-screen.Db0E_BrK.js";import{t as a}from"./chunks/macos-settings.e7FrcLCc.js";import{t as o}from"./chunks/updating-fabric.1C0PZ95m.js";const s=JSON.parse(`{"title":"Обновление Fabric на macOS","description":"Пошаговое руководство по обновлению Fabric на macOS.","frontmatter":{"title":"Обновление Fabric на macOS","description":"Пошаговое руководство по обновлению Fabric на macOS.","authors":["IMB11","modmuss50"],"next":false,"files":[]},"headers":[],"relativePath":"ru_ru/players/updating-fabric/macos.md","filePath":"translated/ru_ru/players/updating-fabric/macos.md","lastUpdated":1770561656000}`);var c={name:`ru_ru/players/updating-fabric/macos.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Обновление Fabric на macOS <a class="header-anchor" href="#h1" aria-label="Permalink to “Обновление Fabric на macOS”">​</a></h1><h2 id="1-download-the-fabric-installer" tabindex="-1">1. Загрузка установщика Fabric <a class="header-anchor" href="#1-download-the-fabric-installer" aria-label="Permalink to “1. Загрузка установщика Fabric”">​</a></h2><p>Загрузите версию Fabric Installer в формате <code>.jar</code> с <a href="https://fabricmc.net/use/" target="_blank" rel="noreferrer">веб-сайта Fabric</a>, нажав на кнопку <code>Download installer (Universal/.JAR)</code>.</p><h2 id="2-run-the-fabric-installer" tabindex="-1">2. Запуск установщика Fabric <a class="header-anchor" href="#2-run-the-fabric-installer" aria-label="Permalink to “2. Запуск установщика Fabric”">​</a></h2><p>Перед запуском установщика закройте Minecraft и Minecraft Launcher.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Вы можете получить предупреждение о том, что Apple не смогла проверить файл <code>.jar</code>. Чтобы обойти это, откройте «Настройки системы» &gt; «Конфиденциальность и безопасность», затем нажмите «Открыть в любом случае». Подтвердите и введите пароль администратора, если будет предложено.</p><p><img src="/assets/players/installing-fabric/macos-settings.png" alt="Настройки системы macOS" loading="lazy"></p></div><p>После запуска установщика вы должны увидеть экран, похожий на этот:</p><p><img src="/assets/players/installing-fabric/installer-screen.png" alt="Установщик Fabric с подсвеченным «Установить»" loading="lazy"></p><p>Убедитесь, что версия новой игры и версия Loader правильные, затем нажмите «Установить», чтобы обновить Fabric.</p><div class="warning custom-block"><p class="custom-block-title">ВАЖНО</p><p>Обязательно снимите флажок «Создать профиль» при запуске программы установки!</p></div><h2 id="3-update-launcher-profile" tabindex="-1">3. Обновление профиля в Minecraft Launcher <a class="header-anchor" href="#3-update-launcher-profile" aria-label="Permalink to “3. Обновление профиля в Minecraft Launcher”">​</a></h2><p>После завершения установки откройте Minecraft Launcher. Затем перейдите на вкладку «Установки». Найдите свой профиль Fabric и откройте экран его редактирования:</p><p><img src="/assets/players/updating-fabric.png" alt="Обновление версии Fabric Loader в Minecraft Launcher" loading="lazy"></p><p>Замените версию на новую версию Fabric Loader, которую вы только что установили, и нажмите «Сохранить».</p><h2 id="4-you-re-done" tabindex="-1">4. Готово! <a class="header-anchor" href="#4-you-re-done" aria-label="Permalink to “4. Готово!”">​</a></h2><p>Выполнив эти шаги, вы можете вернуться на вкладку <code>Играть</code>, выбрать профиль Fabric из раскрывающегося списка в левом нижнем углу и нажмите играть!</p><p>Если у вас возникнут проблемы при выполнении инструкций этого руководства, вы можете обратиться за помощью в <a href="https://discord.fabricmc.net/" target="_blank" rel="noreferrer">Fabric Discord</a> в канале <code>#player-support</code>.</p>`,17)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};